        this.map = new Map();
    }

    get(key: any): any {
        if (!this.map.has(key)) return undefined;
        const v = this.map.get(key);
        this.map.delete(key);
        this.map.set(key, v);
        return v;
    }

    put(key: any, value: any): void {
