class RecencyList<K> {
    private order: K[] = [];

    touch(key: K): void {
        const idx = this.order.indexOf(key);
        if (idx >= 0) this.order.splice(idx, 1);
        this.order.push(key);
    }

    evictOldest(): K | undefined {
        return this.order.shift();
    }

    size(): number {
        return this.order.length;
    }
}

export class LRUCache<K, V> {
    private readonly capacity: number;
    private readonly store = new Map<K, V>();
    private readonly recency = new RecencyList<K>();

    constructor(capacity: number) {
        this.capacity = capacity;
    }

    get(key: K): V | undefined {
        if (!this.store.has(key)) return undefined;
        this.recency.touch(key);
        return this.store.get(key);
    }

    put(key: K, value: V): void {
        this.store.set(key, value);
        this.recency.touch(key);
        if (this.store.size > this.capacity) {
            const evict = this.recency.evictOldest();
            if (evict !== undefined) this.store.delete(evict);
        }
    }

    size(): number {
        return this.store.size;
    }
}

class LRUCache<K, V> {
    private readonly capacity: number;
    private readonly entries = new Map<K, V>();
    protected hits = 0;
    protected misses = 0;

    constructor(capacity: number) {
        this.capacity = capacity;
    }

    get(key: K): V | undefined {
        const v = this.entries.get(key);
        if (v === undefined) {
            this.misses++;
            return undefined;
        }
        this.hits++;
        this.entries.delete(key);
        this.entries.set(key, v);
        return v;
    }

    put(key: K, value: V): void {
        if (this.entries.has(key)) this.entries.delete(key);
        else if (this.entries.size >= this.capacity) {
            const oldest = this.entries.keys().next().value as K;
            this.entries.delete(oldest);
        }
        this.entries.set(key, value);
    }

    size(): number {
        return this.entries.size;
    }

    hitRate(): number {
        const total = this.hits + this.misses;
        return total === 0 ? 0 : this.hits / total;
    }
}

export class CountingLRUCache<K, V> extends LRUCache<K, V> {
    public stats(): { hits: number; misses: number } {
        return { hits: this.hits, misses: this.misses };
    }
}

interface Cache<K, V> {
    get(key: K): V | undefined;
    put(key: K, value: V): void;
    size(): number;
}

abstract class AbstractEvictingCache<K, V> implements Cache<K, V> {
    protected readonly entries = new Map<K, V>();
    constructor(protected readonly capacity: number) {}

    abstract get(key: K): V | undefined;

    put(key: K, value: V): void {
        if (this.entries.has(key)) this.entries.delete(key);
        else if (this.entries.size >= this.capacity) this.evict();
        this.entries.set(key, value);
    }

    protected abstract evict(): void;

    size(): number {
        return this.entries.size;
    }
}

export class LRUCache<K, V> extends AbstractEvictingCache<K, V> {
    get(key: K): V | undefined {
        const v = this.entries.get(key);
        if (v === undefined) return undefined;
        this.entries.delete(key);
        this.entries.set(key, v);
        return v;
    }

    protected evict(): void {
        const oldest = this.entries.keys().next().value as K;
        this.entries.delete(oldest);
    }
}

#include <vector>
#include <climits>
using namespace std;

vector<long long> dijkstra(int n, const vector<vector<pair<int,int>>>& graph, int source) {
    vector<long long> dist(n, INT_MAX);
    vector<bool> visited(n, false);
    dist[source] = 0;

    for (int i = 0; i < n; i++) {
        int u = -1;
        long long best = INT_MAX;
        for (int j = 0; j < n; j++) {
            if (!visited[j] && dist[j] < best) {
                best = dist[j];
                u = j;
            }
        }
        if (u == -1) break;
        visited[u] = true;
        for (int k = 0; k < (int)graph[u].size(); k++) {
            int v = graph[u][k].first;
            int w = graph[u][k].second;
            if (dist[u] + w < dist[v]) {
                dist[v] = dist[u] + w;
            }
        }
    }
    return dist;
}

