static void dfs(int u,
                long long acc,
                const std::vector<std::vector<std::pair<int,int>>>& graph,
                std::vector<long long>& dist,
                std::vector<bool>& on_path) {
    if (acc >= dist[u]) return;
    dist[u] = acc;
    on_path[u] = true;
    for (auto& [v, w] : graph[u]) {
        if (!on_path[v]) {
            dfs(v, acc + w, graph, dist, on_path);
        }
    }
    on_path[u] = false;
}

