        for (auto& [v, w] : graph[u]) {
            if (d + w < dist[v]) {
                dist[v] = d + w;
                pq.push({dist[v], v});
            }
            if (d + w == dist[v] && parent[v] == -1) {
                parent[v] = u;
            }
        }
    }
    return dist;
}

